# typed: strict

class UserService
  extend T::Sig

  sig { params(ids: T::Array[Integer]).returns(T::Hash[Integer, String]) }
  def fetch_names(ids)
    User.where(id: ids).pluck(:id, :name).to_h
  end

  sig { params(user: T.nilable(User)).returns(String) }
  def display_name(user)
    T.must(user).name
  end
end

# Ruby shines: expressive DSL via method_missing
class QueryBuilder
  def initialize = (@conditions = [])

  def method_missing(name, value)
    tap { @conditions << "#{name} = #{value.inspect}" }
  end

  def to_sql = "WHERE #{@conditions.join(' AND ')}"
end

puts QueryBuilder.new.status("active").role("admin").to_sql
# => WHERE status = "active" AND role = "admin"

